import React from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { User, LogOut, LayoutDashboard, UserPlus } from 'lucide-react';

const Header = ({ isLoggedIn, userRole, cerrarSesion }) => {
  const navigate = useNavigate();
  
  // Obtenemos el nombre real guardado en el login, si no existe usamos el username o "Usuario"
  const nombreUsuario = localStorage.getItem('user-name') || localStorage.getItem('user-username') || "Usuario";

  return (
    <header style={headerContainer}>
      {/* LOGO: Al hacer clic siempre lleva al Home */}
      <div style={logoSection} onClick={() => navigate('/')}>
        <span style={logoWhite}>OFERTAS</span>
        <span style={logoOrange}>APP</span>
      </div>

      <nav style={navLinks}>
        {!isLoggedIn ? (
          /* --- ESTADO: NO LOGUEADO --- */
          <>
            <Link to="/registro" style={linkWhite}>
              <UserPlus size={18} /> 
              <span>Crear una cuenta</span>
            </Link>
            <Link to="/login" style={loginButton}>Ingresar</Link>
          </>
        ) : (
          /* --- ESTADO: LOGUEADO --- */
          <div style={{ display: 'flex', alignItems: 'center', gap: '20px' }}>
            
            {/* Mensaje de Bienvenida Personalizado */}
            <div style={userInfo}>
              <User size={16} color="#94a3b8" />
              <span style={{ color: 'white', fontSize: '0.9rem' }}>
                Hola, <strong style={{ color: '#e67e22' }}>{nombreUsuario}</strong>
              </span>
            </div>

            {/* BOTÓN DINÁMICO SEGÚN ROL:
                Si es vendedor -> Dashboard (Mapa/Mis Locales)
                Si es cliente -> Panel Cliente (Buscador de Ofertas)
            */}
            <button 
              onClick={() => navigate(userRole === 'vendedor' ? '/dashboard' : '/panel-cliente')} 
              style={panelButton}
            >
              <LayoutDashboard size={18} />
              <span>{userRole === 'vendedor' ? 'Mi Comercio' : 'Ver Ofertas'}</span>
            </button>
            
            {/* BOTÓN CERRAR SESIÓN */}
            <button 
              onClick={() => {
                cerrarSesion();
                navigate('/');
              }} 
              style={logoutBtn}
              title="Cerrar Sesión"
            >
              <LogOut size={20} />
            </button>
          </div>
        )}
      </nav>
    </header>
  );
};

// --- ESTILOS ACTUALIZADOS ---
const headerContainer = { 
  display: 'flex', 
  justifyContent: 'space-between', 
  alignItems: 'center', 
  padding: '0 5%', 
  background: '#1e293b', 
  height: '75px', 
  position: 'sticky', 
  top: 0, 
  zIndex: 1000,
  boxShadow: '0 4px 10px rgba(0,0,0,0.1)'
};

const logoSection = { cursor: 'pointer', fontSize: '1.6rem', fontWeight: '800', letterSpacing: '-1px' };
const logoWhite = { color: '#ffffff' };
const logoOrange = { color: '#e67e22', marginLeft: '2px' };

const navLinks = { display: 'flex', alignItems: 'center', gap: '25px' };

const linkWhite = { 
  color: '#cbd5e1', 
  textDecoration: 'none', 
  fontSize: '0.9rem', 
  display: 'flex', 
  alignItems: 'center', 
  gap: '8px',
  transition: '0.3s'
};

const loginButton = { 
  background: '#e67e22', 
  color: 'white', 
  padding: '10px 22px', 
  borderRadius: '10px', 
  textDecoration: 'none', 
  fontWeight: 'bold',
  fontSize: '0.9rem',
  boxShadow: '0 4px 12px rgba(230, 126, 34, 0.2)'
};

const userInfo = {
  display: 'flex',
  alignItems: 'center',
  gap: '8px',
  background: 'rgba(255,255,255,0.05)',
  padding: '6px 12px',
  borderRadius: '8px'
};

const panelButton = { 
  background: 'rgba(230, 126, 34, 0.1)', 
  color: '#e67e22', 
  border: '1px solid #e67e22', 
  padding: '8px 18px', 
  borderRadius: '10px', 
  cursor: 'pointer', 
  display: 'flex', 
  alignItems: 'center', 
  gap: '8px', 
  fontWeight: 'bold',
  fontSize: '0.9rem',
  transition: '0.3s'
};

const logoutBtn = { 
  background: 'none', 
  border: 'none', 
  color: '#94a3b8', 
  cursor: 'pointer',
  display: 'flex',
  alignItems: 'center',
  padding: '5px',
  transition: '0.3s hover',
  ':hover': { color: '#ff4d4d' } // Nota: El hover en inline style no funciona así, pero queda la intención
};

export default Header;
